{"code":"import json, re
import pandas as pd

def load_records(var):
    if isinstance(var, str):
        with open(var, 'r', encoding='utf-8') as f:
            return json.load(f)
    return var

books = load_records(var_call_36znDMBtOkeNr9riqxGiO73s)
bdf = pd.DataFrame(books)
first = bdf.loc[0,'details']

pat_raw = r'\b(\d{4})\b'
pat = re.compile(pat_raw)

print('__RESULT__:')
print(json.dumps({
    'pattern': pat_raw,
    're_findall': re.findall(pat_raw, first),
    'compiled_findall': pat.findall(first),
    'search': pat.search(first).group(1) if pat.search(first) else None
}))"}

